<?php declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';$admin=vp3_require_admin_permission('orders.view');$id=(int)vp3_input('id');if(vp3_method()==='POST'){vp3_require_admin_permission('orders.manage');vp3_verify_csrf();$order=vp3_input('order_status');$pay=vp3_input('payment_status');$allowedO=['pending','processing','completed','cancelled','refunded'];$allowedP=['pending','paid','failed','refunded','partially_refunded'];if(in_array($order,$allowedO,true)&&in_array($pay,$allowedP,true))vp3_db()->prepare('UPDATE orders SET order_status=?,payment_status=?,paid_at=IF(?=\'paid\',COALESCE(paid_at,NOW()),paid_at),updated_at=NOW() WHERE id=?')->execute([$order,$pay,$pay,$id]);vp3_audit('admin',(int)$admin['id'],'order.status_updated','order',(string)$id,['order_status'=>$order,'payment_status'=>$pay]);vp3_redirect('admin/order.php?id='.$id);} $s=vp3_db()->prepare('SELECT o.*,c.name customer_name,c.email FROM orders o JOIN customers c ON c.id=o.customer_id WHERE o.id=?');$s->execute([$id]);$row=$s->fetch();if(!is_array($row)){http_response_code(404);exit('Order not found.');}$items=vp3_db()->prepare('SELECT * FROM order_items WHERE order_id=?');$items->execute([$id]);$pageTitle='Order';require VP3_ROOT.'/includes/admin-header.php';?><h1><?=vp3_e($row['order_number'])?></h1><div class="grid two"><article class="card"><h3><?=vp3_e($row['customer_name'])?></h3><p><?=vp3_e($row['email'])?></p><p>Total: <?=vp3_e(vp3_money((int)$row['total_cents'],$row['currency']))?></p></article><form class="card" method="post"><?=vp3_csrf_field()?><div class="field"><label>Order status</label><select name="order_status"><?php foreach(['pending','processing','completed','cancelled','refunded'] as $st):?><option <?=$row['order_status']===$st?'selected':''?>><?=$st?></option><?php endforeach;?></select></div><div class="field"><label>Payment status</label><select name="payment_status"><?php foreach(['pending','paid','failed','refunded','partially_refunded'] as $st):?><option <?=$row['payment_status']===$st?'selected':''?>><?=$st?></option><?php endforeach;?></select></div><button class="button">Update order</button></form></div><h2>Items</h2><div class="table-wrap"><table class="table"><?php foreach($items->fetchAll() as $i):?><tr><td><?=vp3_e($i['item_name'])?></td><td><?=vp3_e(vp3_money((int)$i['total_cents']))?></td></tr><?php endforeach;?></table></div><?php require VP3_ROOT.'/includes/admin-footer.php';?>